import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../../api/axios";

export default function MyAppointments() {
  const [appointments, setAppointments] = useState([]);
  const navigate = useNavigate();
  const [deleting, setDeleting] = useState(null);

  useEffect(() => {
    api.get("/customer/appointments/my")
      .then((res) => setAppointments(res.data))
      .catch((err) => alert(err.response?.data?.message || "Failed to load"));
  }, []);

  const deleteAppointment = async (id) => {
    if (window.confirm("Are you sure you want to cancel this appointment?")) {
      setDeleting(id);
      try {
        const response = await api.delete(`/customer/appointments/${id}`);
        setAppointments(appointments.filter(a => a._id !== id));
        alert("Appointment cancelled successfully");
      } catch (err) {
        console.error("Error cancelling appointment:", err);
        const errorMsg = err.response?.data?.message || err.message || "Failed to cancel appointment";
        alert(errorMsg);
      } finally {
        setDeleting(null);
      }
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">My Appointments</div>
          <div className="pageSub">View and manage your bookings</div>
        </div>
        <button onClick={() => navigate("/book-appointment")} className="btn btnPrimary">
          + Book New Appointment
        </button>
      </div>

      {appointments.length === 0 ? (
        <div className="card cardPad" style={{ maxWidth: 720, margin: "32px auto", textAlign: "center" }}>
          <p style={{ color: "var(--text-light)", fontSize: "16px", marginBottom: "16px" }}>No appointments yet</p>
          <button onClick={() => navigate("/book-appointment")} className="btn btnPrimary">
            Book Your First Appointment
          </button>
        </div>
      ) : (
        <div style={{ maxWidth: 800, margin: "24px auto" }}>
          {appointments.map((a) => (
            <div
              key={a._id}
              className="card"
              style={{
                marginBottom: 16,
                padding: 16,
                borderLeft: `4px solid ${a.status === "completed" ? "#4CAF50" : a.status === "cancelled" ? "#f44336" : "#2196F3"}`,
              }}
            >
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 12 }}>
                <div>
                  <div style={{ fontSize: "12px", color: "var(--text-light)", fontWeight: "600", textTransform: "uppercase", marginBottom: 4 }}>Vehicle</div>
                  <div style={{ fontSize: "16px", fontWeight: "500", color: "var(--text)" }}>
                    {a.vehicle?.brand} {a.vehicle?.model || a.vehicle?.type || ""}
                  </div>
                  <div style={{ fontSize: "13px", color: "var(--text-light)", marginTop: 4 }}>
                    {a.vehicle?.year}
                  </div>
                </div>
                <div>
                  <div style={{ fontSize: "12px", color: "var(--text-light)", fontWeight: "600", textTransform: "uppercase", marginBottom: 4 }}>Status</div>
                  <div style={{
                    display: "inline-block",
                    padding: "6px 12px",
                    borderRadius: "4px",
                    fontSize: "13px",
                    fontWeight: "600",
                    backgroundColor: a.status === "completed" ? "rgba(76, 175, 80, 0.1)" : a.status === "cancelled" ? "rgba(244, 67, 54, 0.1)" : "rgba(33, 150, 243, 0.1)",
                    color: a.status === "completed" ? "#4CAF50" : a.status === "cancelled" ? "#f44336" : "#2196F3",
                    textTransform: "capitalize"
                  }}>
                    {a.status}
                  </div>
                </div>
              </div>

              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16, paddingBottom: 16, borderBottom: "1px solid var(--border)" }}>
                <div>
                  <div style={{ fontSize: "12px", color: "var(--text-light)", fontWeight: "600", textTransform: "uppercase", marginBottom: 4 }}>Date</div>
                  <div style={{ fontSize: "15px", color: "var(--text)", fontWeight: "500" }}>
                    {new Date(a.date).toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric", year: "numeric" })}
                  </div>
                </div>
                <div>
                  <div style={{ fontSize: "12px", color: "var(--text-light)", fontWeight: "600", textTransform: "uppercase", marginBottom: 4 }}>Time</div>
                  <div style={{ fontSize: "15px", color: "var(--text)", fontWeight: "500" }}>
                    {a.time}
                  </div>
                </div>
              </div>

              {a.staffMember && (
                <div style={{ marginBottom: 16, paddingBottom: 16, borderBottom: "1px solid var(--border)" }}>
                  <div style={{ fontSize: "12px", color: "var(--text-light)", fontWeight: "600", textTransform: "uppercase", marginBottom: 4 }}>Assigned Staff Member</div>
                  <div style={{ fontSize: "15px", color: "var(--text)", fontWeight: "500" }}>
                    {a.staffMember.name}
                  </div>
                  {a.staffMember.email && (
                    <div style={{ fontSize: "13px", color: "var(--text-light)", marginTop: 4 }}>
                      {a.staffMember.email}
                    </div>
                  )}
                </div>
              )}

              <div style={{ display: "flex", gap: 8 }}>
                <button
                  onClick={() => navigate(`/edit-my-appointment/${a._id}`)}
                  className="btn"
                  disabled={a.status !== "scheduled"}
                  title={a.status !== "scheduled" ? "Can only edit scheduled appointments" : "Edit appointment"}
                  style={{ opacity: a.status !== "scheduled" ? 0.5 : 1 }}
                >
                  Edit
                </button>
                <button
                  onClick={() => deleteAppointment(a._id)}
                  className="btn"
                  disabled={a.status !== "scheduled" || deleting === a._id}
                  title={a.status !== "scheduled" ? "Can only cancel scheduled appointments" : "Cancel appointment"}
                  style={{ 
                    opacity: a.status !== "scheduled" ? 0.5 : 1,
                    backgroundColor: deleting === a._id ? "#f0f0f0" : "#fff",
                    color: deleting === a._id ? "#999" : "#dc3545",
                    borderColor: deleting === a._id ? "#ddd" : "#dc3545"
                  }}
                >
                  {deleting === a._id ? "Cancelling..." : "Cancel"}
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
